import LocalErrorBoundary from "../LocalErrorBoundary";
import AllianceSelection from "./AllianceSelection";
import {AdvancementConfig,TeamData} from "ftc-common/javaTypes";
import { createRoot } from "react-dom/client";

declare global {
    interface Window {
        eventCode: string,
        eventName: string,
        isDivision: boolean,
        divisionName: string,
        totalTeamCount: number,
        divisionNames: string[],
        seasonName: string,
        presentingSponsor: string,
        advancement?: AdvancementConfig,
        teamData: Record<number, TeamData>
    }
}
const container = document.getElementById('reactContainer');
if(!container) {
    console.error("Mount point for container not found")
} else {
    const root = createRoot(container);
    root.render(<LocalErrorBoundary>
        <AllianceSelection code={window.eventCode} eventName={window.eventName} seasonName={window.seasonName}
                           presentingSponsor={window.presentingSponsor} advancement={window.advancement} teamData={window.teamData}
                           isDivision={window.isDivision} divisionName={window.divisionName} totalTeamCount={window.totalTeamCount}
                           divisionNames={window.divisionNames} />
    </LocalErrorBoundary>);
}