import {usePersistentWebsocket} from "ftc-common/utils";
import {AdvancementConfig, SelectionMethod, SelectionOp, SelectionState, TeamData} from "ftc-common/javaTypes";
import {ReactNode, useState} from "react";
import {t} from "ftc-common/i18n";

import './AllianceSelection.css';
import {Button, Modal, ToggleButton, ToggleButtonGroup} from "react-bootstrap";
import {submitSelection, undoSelection} from "../matchControl/api/allianceSelection";
import {useEffect} from "react";
import {Temporal} from "temporal-polyfill";

function TeamSelection({ selectionState, promptSelection }: { selectionState: SelectionState, promptSelection: (number: number) => void }) {
    let skipFirst = false
    if(selectionState.nextSlot % 2 ==0 && selectionState.nextSlot < (selectionState.alliances.length * 2)) {
        skipFirst = true
    }
    const availableTeams = selectionState.teams.filter(t => !t.removed && !t.captain && !t.picked).slice(skipFirst ? 1 : 0)
    return <div className={"teamSelectionList"}>
        {availableTeams.map(t => {
            return <div key={t.number} className={`${t.declined ? 'declined' : ''}`}><span className={"rank"}>{t.rank}</span> <Button size={"sm"} variant={"outline-dark"} onClick={() => promptSelection(t.number)} disabled={t.declined}>{t.displayNumber}</Button> {t.name}</div>
        })}
    </div>;
}

const ordinals: Record<number, string> = {
    [1]: t`1st`,
    [2]: t`2nd`,
    [3]: t`3rd`,
    [4]: t`4th`,
    [5]: t`5th`,
    [6]: t`6th`,
    [7]: t`7th`,
    [8]: t`8th`,
    [9]: t`9th`,
}

export default function AllianceSelection({code, eventName, seasonName, presentingSponsor, advancement, teamData, isDivision, divisionName, totalTeamCount, divisionNames}:
    {code: string, eventName: string, seasonName: string, presentingSponsor: string, advancement?: AdvancementConfig,
        teamData: Record<number, TeamData>, isDivision: boolean, divisionName: string, totalTeamCount: number, divisionNames: string[]}) {
    const [selectionState, setSelectionState] = useState<SelectionState>();
    const { isConnected, send } = usePersistentWebsocket<SelectionState>(`/stream/allianceselection/?code=${code}`, (data) => {
        setSelectionState(data)
    });

    function setActiveSelection(num: number | null) {
        // Ensure we don't need a server round trip for the selection to show up locally
        setSelectionState((was) => (was ? {...was, activeSelection: num} as SelectionState : undefined))
        send(JSON.stringify({
            type: 'SET_ACTIVE_SELECTION',
            value: num
        }))
    }

    function setDivisionsTogether(val: boolean) {
        // Ensure we don't need a server round trip for the selection to show up locally
        setSelectionState((was) => (was ? {...was, divisionsTogether: val} as SelectionState : undefined))
        send(JSON.stringify({
            type: 'SET_DIVISIONS_TOGETHER',
            value: val
        }))
    }

    useEffect(() => {
        setActiveSelection(null);
    }, [selectionState?.nextSlot])

    const activeSelectionStatus = selectionState?.activeSelection ? selectionState.teams.find(t => t.number == selectionState.activeSelection && !t.removed && !t.declined && !t.captain && !t.picked) : null
    if(!selectionState) {
        return <p>
            {t`Alliance selection has not yet been started by the scorekeeper.`}
        </p>
    }

    let body: ReactNode = "";

    const undoButton = <Button variant={"outline-danger"} onClick={() => { setActiveSelection(null); undoSelection(code) }} className={"mb-2"}>{t`Undo`}</Button>
    const totalTeams = selectionState.teams.length
    const allianceCount = selectionState.alliances.length
    const threeTeamAlliances = selectionState.teamsPerAlliance == 3
    const isDone = (threeTeamAlliances ? selectionState.nextSlot == (allianceCount * 3) : selectionState.nextSlot == (allianceCount * 2)) || selectionState.teams.filter(t => !t.removed && !t.declined && !t.captain && !t.picked)?.length == 0
    const isAlmostDone = (threeTeamAlliances ? selectionState.nextSlot == (allianceCount * 3 - 1) : selectionState.nextSlot == (allianceCount * 2 - 2)) || selectionState.teams.filter(t => !t.removed && !t.declined && !t.captain && !t.picked)?.length == 1
    const {divisionsTogether, activeSelection} = selectionState;

    if(selectionState.nextSlot < 2) {
        const reversedAlliances = [...selectionState.alliances].reverse()
        const captains = reversedAlliances.map(a => teamData[a[0]])
        body = <>
            {isDivision ? <div className={"alert alert-warning"}>
                <p>
                This is alliance selection for the <b>{divisionName}</b> division.
                </p>
                <p>
                Please indicate if you will be running multiple independent ceremonies for each division or one unified ceremony:
                <ToggleButtonGroup name="divisionsTogether" type="radio" value={divisionsTogether ? 1 : 0} onChange={(val) => setDivisionsTogether(val == 1)}>
                    <ToggleButton variant="outline-secondary" value={0}>Independent</ToggleButton>
                    <ToggleButton variant="outline-secondary" value={1}>Together</ToggleButton>
                </ToggleButtonGroup>
                </p>

                {divisionsTogether ? <p>
                    Since you will be running alliance selection for both divisions together, you should run through the complete script for the first division,
                    and then for the other division(s) only read through the script after "Teams, please come on up here when you hear your team number and name called.".
                </p> : null}
            </div> : null}
            <div className={"alert alert-info"}>
                Before starting alliance selection, make sure all teams have a representative present.  If a team will
                not be able to participate in the playoff matches, please let the scorekeeper know so they can be
                marked unavailable and this event will have the appropriate number of alliances.
            </div>
            <p>
                WOW what a great day of qualification matches so far!
            </p>
            {isDivision && !divisionsTogether ? <p>
                It's now time to move onto the playoff portion of the competition! But first, with {totalTeams} teams
                competing today we need to form the {allianceCount} alliances that will compete to represent
                the {divisionName} division in the event playoffs to become the {seasonName} presented
                by {presentingSponsor} winners, here at {eventName}.
            </p>: <p>
                It's now time to move onto the playoff portion of the competition! But first, with {totalTeamCount} teams
                competing today we need to form the {allianceCount} alliances {isDivision && divisionsTogether ? ` for each division ` : " "} that
                will compete to become the {seasonName} presented by {presentingSponsor} winners, here at {eventName}.
            </p>}
            <p>
                Here is how we select alliances:
            </p>
            <p>
                We will invite up a student representative, the Alliance Captain, of the number one ranked team to join us on the field.
                After the nubmer one ranked team makes their selection, we will invite up the next highest ranked and unpicked team
                to make their selection.
            </p>

            {threeTeamAlliances ? <p>
                We continue this process until all {allianceCount} alliances have made their first pick. We repeat this
                process, this time starting with the number {allianceCount} seed alliance and moving up to the number one seed
                alliance, until we have {allianceCount} complete alliances{isDivision && divisionsTogether ? ' for each division' : ''},
                with each made up of three teams.
            </p>
            : <p>
                We continue this process until we have {allianceCount} complete alliances{isDivision && divisionsTogether ? ' for each division' : ''}.
                Each alliance will be made up of two teams.
            </p>}
            <p>
                After an alliance captain extends an invitation to join their alliance, one representative from the
                invited team will join us and either accept or decline the invitation.
            </p>
            <p>
                If a team declines an invitation to become an alliance partner, that team may not be invited to join any
                other alliance. The declining team does not, however, lose their right to select if they become an
                alliance captain.
            </p>
            <p>
                For example: if the number 1 ranked team picks the number {allianceCount} ranked team and they decline,
                the number {allianceCount} ranked team keeps their right to be an alliance captain and the number 1
                ranked team will need to extend the invitation to another team. The number {allianceCount} ranked team
                cannot be invited to join another alliance.
            </p>
            <p>
                If the {ordinals[allianceCount]} ranked team accepts the invitation, the next highest
                ranked team will have the opportunity to become an alliance lead.
            </p>
            <p>
                Throughout the day, teams have been scouting each other to evaluate strengths, weaknesses and possible
                collaborative strategies in the playoff rounds. This is where we see "scouting" come into play as teams
                decide who to partner with. Each alliance captain is looking to make the strongest possible alliance to
                play out the rest of the event with.
            </p>
            <p>
                Once we have {allianceCount} complete alliances, we will begin the playoff matches, which play in a
                double elimination bracket.
            </p>
            <p>
                In a double elimination tournament, all alliances will start off in the upper bracket where they will
                play one match against another alliance. The losing team will drop to the lower bracket and face a new
                alliance in the next round. After they have lost a second time they will be eliminated from the tournament.
            </p>
            {advancement && advancement.advancementCount > 0 ?
              <p>Teams who advance from this event will receive an invitation to {advancement.advancesTo}. This event will be advancing a minimum of {advancement.advancementCount} team(s) to the next event.</p> : null}
            <p>
                There's a lot on the line here.  Teams, please come on up here when you hear your team number and name called.
            </p>
            <div className={"alert alert-info"}>
                Emcee stands where they would like the number one seed alliance to stand.
            </div>
            <p>
                Please welcome the number one seed, team {captains[allianceCount - 1].displayNumber}!<br/>
                {captains[allianceCount - 1].name}<br/>
                {captains[allianceCount - 1].school}<br/>
                {captains[allianceCount - 1].city}, {captains[allianceCount - 1].state}, {captains[allianceCount - 1].country}
            </p>
            <div className={"alert alert-info"}>
                Number one seed comes to the front by the Emcee
            </div>
            <p>
                Now, our number one seed will make the first pick. Which team would you like to invite to join your
                alliance?
            </p>
            <div className={"alert alert-info"}>
                The team should respond with something like "Team {captains[allianceCount - 1].displayNumber} would like to invite team 99999 to be our alliance partner."
            </div>
            {undoButton}
            <TeamSelection selectionState={selectionState} promptSelection={(num) => setActiveSelection(num)}/>
        </>
    } else if(selectionState.nextSlot < (allianceCount * 2) && !isDone) {
        const seed = Math.floor((selectionState.nextSlot) / 2) + 1;
        const captain = teamData[selectionState.alliances[seed - 1][0]]

        body = <>
            {undoButton}
            <p>
                Congratulations! Now we'll move down to the next alliance captain!
            </p>
            <div className={"alert alert-info"}>
                Emcee moves to stand where the {ordinals[seed]} seed captain should stand
            </div>
            <p>
                Let us welcome the captain of our {ordinals[seed]} seed alliance, team {captain.displayNumber}!<br/>
                {captain.name}<br/>
                {captain.school}<br/>
                {captain.city}, {captain.state}, {captain.country}
            </p>
            {isAlmostDone ? <>
                <p>
                    Before we learn who the last alliance captain's selection will be, one last note.
                </p>
                <p>
                    Immediately following the selection, the Head Referee will meet with all the alliance team
                    representatives to cover the rules of the playoffs.
                </p>
                <p>
                    If your team is an alliance lead and you plan to have a different student who is on your drive team
                    serve as your alliance captain during playoffs, we will ask that you have that person ready to send
                    down to the field immediately following alliance selection.
                </p>
            </> : null}
            <p>
                Which team would you like to invite to join your alliance?
            </p>
            <TeamSelection selectionState={selectionState} promptSelection={(num) => setActiveSelection(num)}/>
        </>
    } else if(selectionState.nextSlot == (allianceCount * 2) && !isDone) {
        const seed = allianceCount;
        const captain = teamData[selectionState.alliances[seed - 1][0]]

        body = <>
            {undoButton}
            <p>
                And with that all of our alliances have selected their first partners. We're going to give our
                number {seed} seed alliance a few minutes to discuss who they would like to join them as the third
                member of their alliance.
            </p>
            <div className={"alert alert-info"}>
                Emcee moves to stand by the {ordinals[seed]} seed captain (team {captain.displayNumber} - {captain.name})
            </div>
            <p>
                Which team would you like to invite to complete your alliance?
            </p>
            <TeamSelection selectionState={selectionState} promptSelection={(num) => setActiveSelection(num)}/>
        </>
    } else if(selectionState.nextSlot < (allianceCount * 3) && !isDone) {
        const seed = (allianceCount * 3) - selectionState.nextSlot;
        const captain = teamData[selectionState.alliances[seed - 1][0]]

        body = <>
            {undoButton}
            <p>
                Congratulations! Our number {seed + 1} alliance is now complete. Now we'll move up to the next alliance captain!
            </p>
            <div className={"alert alert-info"}>
                Emcee moves to stand by the {ordinals[seed]} seed captain (team {captain.displayNumber} - {captain.name})
            </div>
            <p>
                Which team would you like to invite to complete your alliance?
            </p>
            <TeamSelection selectionState={selectionState} promptSelection={(num) => setActiveSelection(num)}/>
        </>
    } else if(isDone) {
        body = <>
            {selectionState.immutable ? null : undoButton}
            <p>
                What an exciting tournament it's going to be! Let's hear it with a big round of applause for all the
                teams competing today. Congratulations to everyone for putting in your best effort out on the field!
            </p>
            <p>
                At this time, we need each alliance to send their Alliance Captain to meet with the Head Referee to
                review our tournament rules.
            </p>
            <p>
                We're going to let the alliances talk strategy now and prepare for the playoff matches, which will
                begin at <b>{Temporal.PlainDateTime.from(selectionState.playoffStartTime).toPlainTime().toLocaleString(undefined, { timeStyle: 'short' })}</b>.
            </p>
            <p>
                Remember, awards will be presented during the playoffs—so stick around, cheer loud, and we'll see you back here soon!
            </p>
        </>
    }
    return <>
        <div className={"selectionContent"}>
            {isConnected ? null : <div className={"disconnectedBanner"}>{t`Disconnected!`}</div>}
            {body}
            <div className={"alert alert-info mt-2"}>
                {isDone ? "Final alliances:" : "Current alliances:"}
                <table className={"table"}>
                    <thead>
                    <tr>
                        <th>Captain</th>
                        <th>{threeTeamAlliances ? '1st Pick' : 'Partner'}</th>
                        {threeTeamAlliances ? <th>2nd Pick</th> : null}
                    </tr>
                    </thead>
                    <tbody>
                    {selectionState.alliances.map((alliance, idx) => {
                        const allianceData = alliance.map(a => teamData[a])
                        return <tr key={idx}>
                            <td>{allianceData[0]?.displayNumber}<br/><small>{allianceData[0]?.name}</small></td>
                            <td>{allianceData[1]?.displayNumber}<br/><small>{allianceData[1]?.name}</small></td>
                            {threeTeamAlliances ? <td>{allianceData[2]?.displayNumber}<br/><small>{allianceData[2]?.name}</small></td> : null}
                        </tr>
                    })}
                    </tbody>
                </table>
            </div>
        </div>
        {activeSelection ? <Modal show={!!activeSelectionStatus} onHide={() => setActiveSelection(null)} size="lg" className="teamSelection">
            <Modal.Header closeButton>
                <Modal.Title>{t`Team ${teamData[activeSelection].displayNumber}`}</Modal.Title>
            </Modal.Header>
            <Modal.Body>
                Welcome team {teamData[activeSelection].displayNumber}<br/>
                {teamData[activeSelection].name}<br/>
                {teamData[activeSelection].school}<br/>
                {teamData[activeSelection].city}, {teamData[activeSelection].state}, {teamData[activeSelection].country}
                <div className={"alert alert-info"}>
                    Wait for the team to join the Emcee
                </div>
                <p>
                    {selectionState.alliances.some(a => a[0] == activeSelection) ?
                        `Team ${teamData[activeSelection].displayNumber}, would you prefer to join this alliance or form your own alliance?` :
                        `Team ${teamData[activeSelection].displayNumber}, would you like to join this alliance?`}
                </p>
                <div className={"alert alert-info"}>
                    The team should respond with something like "Team {teamData[activeSelection].displayNumber} accepts." or
                    "Team {teamData[activeSelection].displayNumber} respectfully declines."
                </div>
            </Modal.Body>
            <Modal.Footer>
                <Button variant={"secondary"} onClick={() => setActiveSelection(null)}>{t`Cancel`}</Button>
                <Button variant={"warning"} onClick={() => submitSelection(code, activeSelection, SelectionOp.DECLINE, SelectionMethod.EMCEE)}>{t`Decline`}</Button>
                <Button variant={"primary"} onClick={async () => {
                    await submitSelection(code, activeSelection, SelectionOp.ACCEPT, SelectionMethod.EMCEE)
                    window.scrollTo(0, 0)
                }}>{t`Accept`}</Button>
            </Modal.Footer>
        </Modal> : null}
    </>
}
